class QuizData {
  QuizData({
    String? id,
    String? code,
    String? name,
    int? order,
    int? type,
    bool? isScore,
    bool? isRelatedQuestions,
    bool? isRelatedPatients,
    String? explain,
    dynamic minCompletePercent,
    List<AnswerData>? answers,
    List<ResultData>? results,
  }) {
    _id = id;
    _code = code;
    _name = name;
    _order = order;
    _type = type;
    _isScore = isScore;
    _isRelatedQuestions = isRelatedQuestions;
    _isRelatedPatients = isRelatedPatients;
    _explain = explain;
    _minCompletePercent = minCompletePercent;
    _answers = answers;
    _results = results;
  }

  bool get hasUserAnswer {
    for (final AnswerData answer in answers ?? []) {
      if (answer.isAnswered) return true;
    }
    if(answers?.isEmpty == true){
     // String? accountIdCurrentUser = AppSettings.userInfo?.accountId;
      if(results != null){
     //   if(results!.accountId == accountIdCurrentUser){
          return true;
     //   }
      }
    }
    return false;
  }

  QuizData.fromJson(dynamic json) {
    _id = json['id'];
    _code = json['code'];
    _name = json['name'];
    _order = json['order'];
    _type = json['type'];
    _isScore = json['isScore'];
    _isRelatedQuestions = json['isRelatedQuestions'];
    _isRelatedPatients = json['isRelatedPatients'];
    _explain = json['explain'];
    _minCompletePercent = json['minCompletePercent'];
    if (json['answers'] != null) {
      _answers = [];
      json['answers'].forEach((v) {
        _answers?.add(AnswerData.fromJson(v));
      });
    }

    if (json['result'] != null) {
      _results = [];
      json['result'].forEach((v) {
        _results?.add(ResultData.fromJson(v));
      });
    }
    // if (json['result'] != null) {
    //   _results = ResultData.fromJson(json['result']);
    // }
  }
